import{_ as r,C as c,o,c as i,a3 as a,b as l,w as d,a as n,E as s,a4 as p}from"./chunks/framework.aYYe0dfI.js";const g=JSON.parse('{"title":"Module provider","description":"该模块提供了与 LLM 提供者进行网络通信的核心基础设施，主要负责管理环境配置（如 API 密钥和基础 URL）、构建并验证 HTTP 请求路径、序列化工具调用参数以及解析原始响应。它隐藏了底层的凭证读取、URL 拼接和请求合规性检查等细节，为上层协议模块提供可靠且可复用的底层工具。","frontmatter":{"title":"Module provider","description":"该模块提供了与 LLM 提供者进行网络通信的核心基础设施，主要负责管理环境配置（如 API 密钥和基础 URL）、构建并验证 HTTP 请求路径、序列化工具调用参数以及解析原始响应。它隐藏了底层的凭证读取、URL 拼接和请求合规性检查等细节，为上层协议模块提供可靠且可复用的底层工具。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/provider/index.md","filePath":"zh/clore/modules/provider/index.md"}'),h={name:"zh/clore/modules/provider/index.md"};function u(m,e,f,_,b,v){const t=c("Mermaid");return o(),i("div",null,[e[1]||(e[1]=a('<h1 id="module-provider" tabindex="-1">Module <code>provider</code> <a class="header-anchor" href="#module-provider" aria-label="Permalink to &quot;Module `provider`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>该模块提供了与 LLM 提供者进行网络通信的核心基础设施，主要负责管理环境配置（如 API 密钥和基础 URL）、构建并验证 HTTP 请求路径、序列化工具调用参数以及解析原始响应。它隐藏了底层的凭证读取、URL 拼接和请求合规性检查等细节，为上层协议模块提供可靠且可复用的底层工具。</p><p>在公开实现层面，<code>provider</code> 以 <code>detail</code> 命名空间形式暴露一组内部函数与类型，包括 <code>CredentialEnv</code> 结构体（封装 <code>base_url_env</code> 与 <code>api_key_env</code> 环境变量名）、<code>read_credentials</code>（从环境读取凭证）、<code>append_url_path</code>（规范化拼接路径段）、<code>parse_json_object</code>（安全解析 JSON 对象）、<code>serialize_tool_arguments</code>（将工具参数序列化为字符串）以及 <code>validate_completion_request</code>（校验 completion 请求的结构与语义）。这些元素共同构成了与 LLM 提供者交互的通用工具集，被协议与 schema 模块间接使用。</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./../http/"><code>http</code></a></li><li><a href="./../protocol/"><code>protocol</code></a></li><li><a href="./../schema/"><code>schema</code></a></li><li><code>std</code></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">​</a></h2><ul><li><a href="./../anthropic/"><code>anthropic</code></a></li><li><a href="./../openai/"><code>openai</code></a></li></ul><h2 id="dependency-diagram" tabindex="-1">Dependency Diagram <a class="header-anchor" href="#dependency-diagram" aria-label="Permalink to &quot;Dependency Diagram&quot;">​</a></h2>',9)),(o(),l(p,null,{default:d(()=>[s(t,{id:"mermaid-55",class:"mermaid",graph:"graph%20LR%0A%20%20%20%20M0%5B%22provider%22%5D%0A%20%20%20%20I0%5B%22http%22%5D%0A%20%20%20%20I0%20--%3E%20M0%0A%20%20%20%20I1%5B%22protocol%22%5D%0A%20%20%20%20I1%20--%3E%20M0%0A%20%20%20%20I2%5B%22schema%22%5D%0A%20%20%20%20I2%20--%3E%20M0%0A"})]),fallback:d(()=>[...e[0]||(e[0]=[n(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=a('<h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-net-detail-credentialenv" tabindex="-1"><code>clore::net::detail::CredentialEnv</code> <a class="header-anchor" href="#clore-net-detail-credentialenv" aria-label="Permalink to &quot;`clore::net::detail::CredentialEnv`&quot;">​</a></h3><p>Declaration: <code>network/provider.cppm:14</code></p><p>Definition: <code>network/provider.cppm:14</code></p><p>Declaration: <a href="./../../namespaces/clore/net/detail/"><code>Namespace clore::net::detail</code></a></p><p>结构体 <code>clore::net::detail::CredentialEnv</code> 提供一对 <code>std::string_view</code> 字段：<code>base_url_env</code> 和 <code>api_key_env</code>，分别保存待查找的环境变量名称，用于在运行时获取服务的基础 URL 和 API 密钥。该结构体仅作为纯数据聚合，不包含任何构造函数或成员函数，其不变性由调用方保证——两个字段指向的字符串视图必须引用具有静态存储期的字符串字面量或由调用方管理的持久缓冲区。</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li><code>base_url_env</code> and <code>api_key_env</code> should point to valid, immutable string views</li><li>No invariants are enforced by the struct; callers are responsible for ensuring the string views remain valid</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>base_url_env</code></li><li><code>api_key_env</code></li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to pass environment variable names to credential retrieval logic</li><li>Likely instantiated in higher-level credential handling code</li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-net-detail-append-url-path" tabindex="-1"><code>clore::net::detail::append_url_path</code> <a class="header-anchor" href="#clore-net-detail-append-url-path" aria-label="Permalink to &quot;`clore::net::detail::append_url_path`&quot;">​</a></h3><p>Declaration: <code>network/provider.cppm:21</code></p><p>Definition: <code>network/provider.cppm:43</code></p><p>Declaration: <a href="./../../namespaces/clore/net/detail/"><code>Namespace clore::net::detail</code></a></p><p>该函数通过去除尾部斜杠和头部斜杠来安全拼接 URL 基路径与路径片段。它先将 <code>base_url</code> 拷贝到 <code>url</code> 中，并用一个 <code>while</code> 循环移除末尾连续的 <code>/</code> 字符；再将 <code>path</code> 拷贝到 <code>suffix</code> 中，用另一个 <code>while</code> 循环移除开头的连续 <code>/</code>。若 <code>suffix</code> 非空，则在 <code>url</code> 末尾添加一个 <code>/</code> 后追加 <code>suffix</code>，最终返回拼接后的 <code>std::string</code>。整个实现仅依赖 <code>std::string</code> 与 <code>std::string_view</code> 的基本操作，无外部函数调用或复杂依赖。</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>base_url</code></li><li><code>path</code></li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>building HTTP request <code>URLs</code></li><li>URL path normalization</li></ul><h3 id="clore-net-detail-parse-json-object" tabindex="-1"><code>clore::net::detail::parse_json_object</code> <a class="header-anchor" href="#clore-net-detail-parse-json-object" aria-label="Permalink to &quot;`clore::net::detail::parse_json_object`&quot;">​</a></h3><p>Declaration: <code>network/provider.cppm:27</code></p><p>Definition: <code>network/provider.cppm:148</code></p><p>Declaration: <a href="./../../namespaces/clore/net/detail/"><code>Namespace clore::net::detail</code></a></p><p>函数 <code>clore::net::detail::parse_json_object</code> 封装了 JSON 解析与错误处理的核心流程。它首先调用 <code>json::parse&lt;json::Object&gt;</code> 对输入 <code>raw</code> 进行结构化解析；若返回的 <code>std::expected</code> 不含值，则使用 <code>std::format</code> 将传入的 <code>context</code> 字符串与解析错误信息拼接，构建一个 <code>LLMError</code> 对象并包装为 <code>std::unexpected</code> 返回。该函数直接依赖 <code>json::parse&lt;json::Object&gt;</code> 提供的 JSON 解析能力，并通过 <code>std::format</code> 与 <code>LLMError</code> 实现友好错误报告。</p><p>解析成功时，函数返回经过移动的 <code>json::Object</code> 值；整个过程不涉及任何外部状态或复杂分支，仅聚焦于将 <code>raw</code> 转换为强类型对象的同时保留错误上下文。<code>context</code> 参数通常由调用者传入，用于标识解析场景（如环境变量名或请求路径），以便在失败时定位问题。</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>raw</code> parameter</li><li><code>context</code> parameter</li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>parsing JSON objects from raw strings with error context</li></ul><h3 id="clore-net-detail-read-credentials" tabindex="-1"><code>clore::net::detail::read_credentials</code> <a class="header-anchor" href="#clore-net-detail-read-credentials" aria-label="Permalink to &quot;`clore::net::detail::read_credentials`&quot;">​</a></h3><p>Declaration: <code>network/provider.cppm:19</code></p><p>Definition: <code>network/provider.cppm:39</code></p><p>Declaration: <a href="./../../namespaces/clore/net/detail/"><code>Namespace clore::net::detail</code></a></p><p>函数 <code>clore::net::detail::read_credentials</code> 作为一个轻量代理，将凭据读取工作委托给 <code>read_environment</code>。它接受一个 <code>clore::net::detail::CredentialEnv</code> 实例，从中提取 <code>base_url_env</code> 和 <code>api_key_env</code> 两个字段作为参数直接转发。该函数不执行任何其他逻辑或校验；其内置的控制流即单次函数调用。依赖方面，它直接依赖于 <code>read_environment</code> 的签名和返回类型 <code>std::expected&lt;EnvironmentConfig, LLMError&gt;</code>，以及 <code>clore::net::detail::CredentialEnv</code> 结构体的定义。整个实现仅作为接口适配层，隔离了环境变量读取的具体细节。</p><h4 id="side-effects-2" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-2" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Reads environment variables as performed by the called function <code>read_environment</code>.</li></ul><h4 id="reads-from-2" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-2" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>env.base_url_env</code> (environment variable name for base URL)</li><li><code>env.api_key_env</code> (environment variable name for API key)</li><li>Environment variable storage (indirectly via <code>read_environment</code>)</li></ul><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to obtain base URL and API key from environment variables for network requests.</li><li>Called by higher-level functions that require <code>EnvironmentConfig</code> initialization.</li></ul><h3 id="clore-net-detail-serialize-tool-arguments" tabindex="-1"><code>clore::net::detail::serialize_tool_arguments</code> <a class="header-anchor" href="#clore-net-detail-serialize-tool-arguments" aria-label="Permalink to &quot;`clore::net::detail::serialize_tool_arguments`&quot;">​</a></h3><p>Declaration: <code>network/provider.cppm:30</code></p><p>Definition: <code>network/provider.cppm:158</code></p><p>Declaration: <a href="./../../namespaces/clore/net/detail/"><code>Namespace clore::net::detail</code></a></p><p>该函数首先将输入的 <code>arguments</code> 通过 <code>json::to_string</code> 序列化为字符串。若序列化失败，它会立即用 <code>unexpected_json_error</code> 构造一个包含 <code>context</code> 与序列化错误信息的 <code>LLMError</code> 并返回。若成功，则对得到的字符串执行 <code>json::parse</code> 将其重新解析为 <code>json::Value</code>。解析一旦失败，函数返回一个 <code>std::unexpected</code> 包装的错误，其消息由 <code>std::format</code> 组合出 <code>context</code> 与解析错误描述。当两个步骤均顺利通过后，它返回一个 <code>std::pair</code>，其中包含原始序列化字符串与解析后的 JSON 值，二者均为移动语义。</p><p>整个过程唯一的依赖是 <code>json::to_string</code> 与 <code>json::parse</code> 的健全性，以及 <code>LLMError</code> 和 <code>unexpected_json_error</code> 的错误包装机制。函数本身不参与任何外部状态修改或异步操作，严格遵循先序列化再反序列化的冗余校验模式。</p><h4 id="side-effects-3" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-3" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-3" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-3" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>arguments</code> (parameter)</li><li><code>context</code> (parameter)</li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li>return value via <code>std::expected</code> containing a pair of <code>std::string</code> and <code>json::Value</code></li></ul><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to normalize a JSON value by ensuring it can be serialized and deserialized without loss</li><li>Provides both string and structured representations for downstream processing</li><li>Called when preparing tool arguments for serialization in network requests</li></ul><h3 id="clore-net-detail-validate-completion-request" tabindex="-1"><code>clore::net::detail::validate_completion_request</code> <a class="header-anchor" href="#clore-net-detail-validate-completion-request" aria-label="Permalink to &quot;`clore::net::detail::validate_completion_request`&quot;">​</a></h3><p>Declaration: <code>network/provider.cppm:23</code></p><p>Definition: <code>network/provider.cppm:61</code></p><p>Declaration: <a href="./../../namespaces/clore/net/detail/"><code>Namespace clore::net::detail</code></a></p><p>函数 <code>clore::net::detail::validate_completion_request</code> 对输入的 <code>CompletionRequest</code> 执行分层验证。首先检查 <code>request.model</code> 和 <code>request.messages</code> 是否非空，若为空则立即返回 <code>std::unexpected(LLMError(...))</code>。随后根据参数 <code>validate_response_format_schema</code> 决定是否调用 <code>validate_response_format</code> 验证 <code>request.response_format</code>，并根据 <code>validate_tool_schemas</code> 决定是否遍历 <code>request.tools</code> 并对每一项调用 <code>validate_tool_definition</code>。在工具相关字段上，若 <code>request.tool_choice</code> 或 <code>request.parallel_tool_calls</code> 存在但 <code>request.tools</code> 为空，则报错；若 <code>tool_choice</code> 为 <code>ForcedFunctionToolChoice</code>，还需检查强制调用的工具名是否存在于 <code>request.tools</code> 中。最后遍历 <code>request.messages</code>，通过 <code>std::visit</code> 分派消息类型：对 <code>AssistantToolCallMessage</code> 要求 <code>content</code> 或 <code>tool_calls</code> 非空，且每条 <code>tool_calls</code> 的 <code>id</code> 和 <code>name</code> 非空且 <code>id</code> 无重复；对 <code>ToolResultMessage</code> 要求 <code>tool_call_id</code> 非空。所有检查通过后返回一个空 <code>std::expected&lt;void, LLMError&gt;</code>。该函数依赖内部函数 <code>validate_response_format</code>、<code>validate_tool_definition</code> 及类型 <code>ForcedFunctionToolChoice</code>、<code>AssistantToolCallMessage</code>、<code>ToolResultMessage</code> 和 <code>std::visit</code>、<code>std::get_if</code> 的分发机制。</p><h4 id="side-effects-4" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-4" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-4" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-4" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>request<code>.model</code></li><li>request<code>.messages</code></li><li>request<code>.response_format</code></li><li>request<code>.tools</code></li><li>request<code>.tool_choice</code></li><li>request<code>.parallel_tool_calls</code></li><li>message content</li><li><code>tool_calls</code> entries</li><li><code>tool_call_id</code></li></ul><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called before sending a completion request to ensure validity</li><li>Used in request preparation pipeline</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p>该模块封装了与特定 LLM 提供者进行网络通信的核心逻辑，内部通过 <code>detail</code> 子命名空间将凭据读取、URL 拼接、请求验证和工具参数序列化等底层操作与对外接口解耦。模块依赖关系严格：<code>http</code> 模块提供实际收发能力，<code>protocol</code> 模块定义请求/响应数据结构，<code>schema</code> 模块负责 JSON Schema 生成和校验，通过这种分层隔离了网络层、协议层和元数据层的职责。实现结构上，所有内部函数均通过 <code>int</code> 返回值指示成功或错误（零值表示成功），避免了异常传播，便于上层模块以统一的错误码方式集成和诊断问题。</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../http/">Module http</a></li><li><a href="./../protocol/">Module protocol</a></li><li><a href="./../schema/">Module schema</a></li></ul>',76))])}const x=r(h,[["render",u]]);export{g as __pageData,x as default};
